- "stuck in slow lanes" refers to high delay alerts; 
- "critical moments" refers to events with a severity level of 'critical';
- "typical day" refers to the time slot 'Day'.

sql:
SELECT u.user_id, u.user_name, ns.network_id
FROM users u
JOIN network_selection ns ON u.user_id = ns.user_id;

SELECT network_id
FROM performance_analysis
WHERE total_bytes_transferred = (
  SELECT MAX(total_bytes_transferred)
  FROM performance_analysis
);

SELECT network_name
FROM networks
WHERE network_type = 'LTE' AND max_capacity > 100;

SELECT networks.network_name || ', ' || networks.network_type AS network_info
FROM networks
JOIN network_selection ON networks.network_id = network_selection.network_id;

SELECT AVG(l.severity_level) as average_severity_level
FROM logs l
WHERE EXISTS (SELECT 1 FROM alerts a WHERE a.alert_id = l.log_id);
